class Solution {
    public int maxLengthBetweenEqualCharacters(String s) {
        int maxLen = -1;
        Map<Character, Integer> firstOccurrence = new HashMap<>();
        Map<Character, Integer> lastOccurrence = new HashMap<>();

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (!firstOccurrence.containsKey(c)) {
                firstOccurrence.put(c, i);
            }
            lastOccurrence.put(c, i);
        }

        for (char c : firstOccurrence.keySet()) {
            maxLen = Math.max(maxLen, lastOccurrence.get(c) - firstOccurrence.get(c) - 1);
        }

        return maxLen;
    }
}
